        const testObject = { name: 'test', value: 42 };

        pull_stream(
            pull_stream.once(testObject),
            pull_stream.collect((err, results) => {
                assert.strictEqual(err, null);
                assert.strictEqual(results.length, 1);
                assert.deepStrictEqual(results[0], testObject);
                done();
            })
        );
    });

    it('test pull-stream.once - should work with null value', function(done) {
        pull_stream(
            pull_stream.once(null),
            pull_stream.collect((err, results) => {
                assert.strictEqual(err, null);
                assert.strictEqual(results.length, 1);
                assert.strictEqual(results[0], null);
                done();
            })
        );
    });

    it('test pull-stream.once - should call onAbort when stream is aborted', function(done) {
        let abortCalled = false;
        const onAbort = () => {
            abortCalled = true;
        };

        const source = pull_stream.once('test', onAbort);

        // Start reading but then abort
        source(null, (end, data) => {
            if (end) return;
            // Abort the stream by calling with true
            source(true, () => {
                // Give a small delay to ensure onAbort is called
                setTimeout(() => {
                    assert.strictEqual(abortCalled, true);
                    done();
                }, 10);
            });
        });
    });

    it('test pull-stream.once - should work without onAbort callback', function(done) {
        const testValue = 123;

        pull_stream(
            pull_stream.once(testValue),
            pull_stream.collect((err, results) => {
                assert.strictEqual(err, null);
                assert.strictEqual(results.length, 1);
                assert.strictEqual(results[0], testValue);
                done();
            })
        );
    });

    it('test pull-stream.once - should end stream after emitting value', function(done) {
        const source = pull_stream.once('test');
        let callCount = 0;

        source(null, function next(end, data) {
            callCount++;
            if (callCount === 1) {
                // First call should return the value
                assert.strictEqual(end, null);
                assert.strictEqual(data, 'test');
                // Call again to check stream ends
                source(null, next);
            } else if (callCount === 2) {
                // Second call should return end=true
                assert.strictEqual(end, true);
                assert.strictEqual(data, undefined);
                done();
            }
        });
    });
