let mocha = require('mocha');
let assert = require('assert');
let pull_stream = require('pull-stream');

function infinite (generate) {
  generate = generate || Math.random
  return function (end, cb) {
    if(end) return cb && cb(end)
    return cb(null, generate())
  }
}

describe('test pull_stream', function() {
    it('test pull-stream.infinite with default Math.random generator', function(done) {
        let stream = infinite();
        let count = 0;
        let values = [];

        function read() {
            stream(false, function(end, data) {
                if (end) return done(end);

                assert(typeof data === 'number', 'Should generate numbers');
                assert(data >= 0 && data < 1, 'Should generate values between 0 and 1');
                values.push(data);
                count++;

                if (count >= 5) {
                    // Check that we got different values (very unlikely to get duplicates with Math.random)
                    let unique = [...new Set(values)];
                    assert(unique.length > 1, 'Should generate different values');
                    done();
                } else {
                    read();
                }
            });
        }

        read();
    });

    it('test pull-stream.infinite with custom generator', function(done) {
        let counter = 0;
        let customGenerator = function() {
            return counter++;
        };

        let stream = infinite(customGenerator);
        let expectedValues = [0, 1, 2];
        let actualValues = [];

        function read() {
            stream(false, function(end, data) {
                if (end) return done(end);

                actualValues.push(data);

                if (actualValues.length >= 3) {
                    assert.deepEqual(actualValues, expectedValues, 'Should generate expected sequence');
                    done();
                } else {
                    read();
                }
            });
        }

        read();
    });

    it('test pull-stream.infinite handles end signal', function(done) {
        let stream = infinite();
        let endError = new Error('Stream ended');

        stream(endError, function(end, data) {
            assert.equal(end, endError, 'Should pass through the end signal');
            assert.equal(data, undefined, 'Should not return data when ended');
            done();
        });
    });

    it('test pull-stream.infinite handles end signal without callback', function(done) {
        let stream = infinite();
        let endError = new Error('Stream ended');

        // Should not throw when no callback is provided
        let result = stream(endError);
        assert.equal(result, undefined, 'Should return undefined when ended without callback');
        done();
    });

    it('test pull-stream.infinite with generator that returns strings', function(done) {
        let words = ['hello', 'world', 'test'];
        let index = 0;
        let stringGenerator = function() {
            return words[index++ % words.length];
        };

        let stream = infinite(stringGenerator);
        let results = [];

        function read() {
            stream(false, function(end, data) {
                if (end) return done(end);

                assert(typeof data === 'string', 'Should generate strings');
                results.push(data);

                if (results.length >= 6) {
                    assert.deepEqual(results, ['hello', 'world', 'test', 'hello', 'world', 'test'], 
                                   'Should cycle through the words');
                    done();
                } else {
                    read();
                }
            });
        }

        read();
    });
});
