            source,
            pull_stream.map(mapper),
            pull_stream.collect(function(err, results) {
                assert.ifError(err);
                assert.deepEqual(results, ['HELLO', 'WORLD', 'TEST']);
                done();
            })
        );
    });

    it('test pull-stream.map with no mapper (identity function)', function(done) {
        const source = pull_stream.values([1, 2, 3]);

        pull_stream(
            source,
            pull_stream.map(),
            pull_stream.collect(function(err, results) {
                assert.ifError(err);
                assert.deepEqual(results, [1, 2, 3]);
                done();
            })
        );
    });

    it('test pull-stream.map with empty stream', function(done) {
        const source = pull_stream.values([]);
        const mapper = x => x * 2;

        pull_stream(
            source,
            pull_stream.map(mapper),
            pull_stream.collect(function(err, results) {
                assert.ifError(err);
                assert.deepEqual(results, []);
                done();
            })
        );
    });

    it('test pull-stream.map with error in mapper function', function(done) {
