                assert.ifError(err);
                assert.deepEqual(results, [
                    { name: 'Alice', age: 26 },
                    { name: 'Bob', age: 31 },
                    { name: 'Charlie', age: 36 }
                ]);
                done();
            })
        );
    });
});
