let mocha = require('mocha');
let assert = require('assert');
let pull_stream = require('pull-stream');

describe('test pull_stream', function() {
    it('test pull-stream.concat with array of strings', function(done) {
        pull_stream(
            pull_stream.values(['hello', ' ', 'world']),
            pull_stream.concat(function(err, result) {
                assert.strictEqual(err, null);
                assert.strictEqual(result, 'hello world');
                done();
            })
        );
    });

    it('test pull-stream.concat with array of buffers', function(done) {
        const buf1 = Buffer.from('hello');
        const buf2 = Buffer.from(' ');
        const buf3 = Buffer.from('world');

        pull_stream(
            pull_stream.values([buf1, buf2, buf3]),
            pull_stream.concat(function(err, result) {
                assert.strictEqual(err, null);
                assert.ok(Buffer.isBuffer(result));
                assert.strictEqual(result.toString(), 'hello world');
                done();
            })
        );
    });

    it('test pull-stream.concat with empty stream', function(done) {
        pull_stream(
            pull_stream.values([]),
            pull_stream.concat(function(err, result) {
                assert.strictEqual(err, null);
                assert.strictEqual(result, '');
                done();
            })
        );
    });

    it('test pull-stream.concat with single value', function(done) {
        pull_stream(
            pull_stream.values(['single']),
            pull_stream.concat(function(err, result) {
                assert.strictEqual(err, null);
                assert.strictEqual(result, 'single');
                done();
            })
        );
    });

    it('test pull-stream.concat with error in stream', function(done) {
        pull_stream(
            function(end, cb) {
                if (end) return cb(end);
                cb(new Error('test error'));
            },
            pull_stream.concat(function(err, result) {
                assert.ok(err instanceof Error);
                assert.strictEqual(err.message, 'test error');
                assert.strictEqual(result, undefined);
                done();
            })
        );
    });
});
